api_calls.content:
{
  "root_cause": "深层动机「救城外营地的人」与表面行为「送样本」之间缺乏直接连接，角色心理链条断裂，读者无法感受到救治进展的即时收益。",
  "motivation_gaps": [
    {
      "character": "韩霜",
      "behavior_quote": "她清晨出发，避开主街，沿墙根走。样本箱扣锁完好，她每百步停一次听动静。",
      "missing_link": "此行为仅服务于样本安全运送，未体现将样本与营地即时救治关联的迫切心理，深层动机「救营地的人」缺少后续获取药物或治疗行为作为支撑。",
      "relation_target": "营地疫情中的患者"
    }
  ],
  "fix_actions": [
    "在韩霜交接样本后，增加她主动询问医师能否立即配备药物、或要求将现成药品带回营地的对话或心理描写。",
    "描写韩霜对三天培养期等待的焦灼情绪，强化她对营地病情的担忧与返程步伐加快的内在联系。",
    "补充韩霜回忆营地具体病人的细节，使送样行为的紧迫感与救人动机直接挂钩。"
  ],
  "acceptance_criteria": [
    "角色行为中明确出现为获取救治手段（如药品、疗法）而做的努力，不再仅止于样本传递。",
    "心理描写呈现救治延迟带来的压力，且与外部行为（如加快步伐、绕路寻药）形成因果呼应。",
    "读者能从韩霜的行动和思绪中明确感知到送样本的必要性及对救人的直接影响。"
  ],
  "evidence_quotes": [
    {
      "paragraph": 1,
      "quote": "韩霜要把样本送到医馆。她清晨出发，避开主街，沿墙根走。样本箱扣锁完好，她每百步停一次听动静。"
    },
    {
      "paragraph": 3,
      "quote": "她原想救城外营地的人，此刻样本已交接，任务链闭合。营地仍缺即时收益，但动机、刺激、行为、结果齐全。"
    }
  ],
  "needs_reroute": false
}
